```from typing import List

def check_for_query(map, row, column, query):
    left = query[0]
    top = query[1]
    bottom = query[2]
    right = query[3]
    for i in range(1, left+1):
        if not column-1 > 0 or not map[row][column-1] == 'E':
            return False
    for i in range(1, top+1):
        if not row-1 > 0 or not map[row-1][column] == 'E':
            return False
    for i in range(1, bottom+1):
        if not column+1 < len(map) or not map[row][column+1] == 'E':
            return False
    for i in range(1, right+1):
        if not row+1 < len(map[0])  or not map[row+1][column] == 'E':
            return False
    return True


def process(map: List[List], query: List):
    row_len = len(map[0])
    column_len = len(map)
    result = []
    for row in range(row_len):
        for column in range(column_len):
            if map[column][row] == 'O':
                if check_for_query(map, row, column, query):
                    result.append([row, column])
    return result```
